import time

def log_agent_step(conversation_id: str, step: dict) -> None:
    """Log an agent step to a Redis Stream for observability."""
    r.xadd(
        steps_key(conversation_id),
        {
            'tool_name':   step.get('tool_name', ''),
            'status':      step.get('status', 'unknown'),
            'duration_ms': str(step.get('duration_ms', 0)),
            'ts':          str(int(time.time() * 1000)),
        },
        maxlen=1000,   # Keep last 1000 steps per conversation
        approximate=True
    )


def get_agent_steps(conversation_id: str, count: int = 50) -> list[dict]:
    """Read recent agent steps from the Stream."""
    entries = r.xrevrange(steps_key(conversation_id), count=count)
    return [
        {'id': entry_id, **{k: v for k, v in fields.items()}}
        for entry_id, fields in entries
    ]

# Health check: verify Redis connectivity and write capability
def redis_health_check() -> dict:
    try:
        r.set('health:ping', '1', ex=10)
        val = r.get('health:ping')
        info = r.info('memory')
        return {
            'status': 'ok',
            'ping': val == '1',
            'used_memory_mb': info['used_memory'] // (1024 * 1024),
            'maxmemory_mb': info.get('maxmemory', 0) // (1024 * 1024),
            'evicted_keys': info.get('evicted_keys', 0),
        }
    except redis.RedisError as e:
        return {'status': 'error', 'error': str(e)}
